  81→// This function determines whether the current segment/side is transparent
  82→//		1 = YES
  83→//		0 = NO
  84→int check_transparency(segment* seg, int side)
  85→{
  86→	if ((seg->sides[side].tmap_num2 & 0x3FFF) == 0) 
  87→	{
  88→		if (GameBitmaps[Textures[seg->sides[side].tmap_num].index].bm_flags & BM_FLAG_TRANSPARENT)
  89→			return 1;
  90→		else
  91→			return 0;
  92→	}
  93→
  94→	if (GameBitmaps[Textures[seg->sides[side].tmap_num2 & 0x3FFF].index].bm_flags & BM_FLAG_SUPER_TRANSPARENT)
  95→		return 1;
  96→	else
  97→		return 0;
  98→}
