 100→//-----------------------------------------------------------------
 101→// This function checks whether we can fly through the given side.
 102→//	In other words, whether or not we have a 'doorway'
 103→//	 Flags:
 104→//		WID_FLY_FLAG				1
 105→//		WID_RENDER_FLAG			2
 106→//		WID_RENDPAST_FLAG			4
 107→//	 Return values:
 108→//		WID_WALL						2	// 0/1/0		wall	
 109→//		WID_TRANSPARENT_WALL		6	//	0/1/1		transparent wall
 110→//		WID_ILLUSORY_WALL			3	//	1/1/0		illusory wall
 111→//		WID_TRANSILLUSORY_WALL	7	//	1/1/1		transparent illusory wall
 112→//		WID_NO_WALL					5	//	1/0/1		no wall, can fly through
 113→int wall_is_doorway(segment* seg, int side)
 114→{
 115→	int flags, type;
 116→	int state;
 117→	//--Covered by macro	// No child.
 118→	//--Covered by macro	if (seg->children[side] == -1)
 119→	//--Covered by macro		return WID_WALL;
 120→
 121→	//--Covered by macro	if (seg->children[side] == -2)
 122→	//--Covered by macro		return WID_EXTERNAL_FLAG;
 123→
 124→	//--Covered by macro // No wall present.
 125→	//--Covered by macro	if (seg->sides[side].wall_num == -1)
 126→	//--Covered by macro		return WID_NO_WALL;
 127→
 128→	Assert(seg - Segments >= 0 && seg - Segments <= Highest_segment_index);
 129→	Assert(side >= 0 && side < 6);
 130→
 131→	type = Walls[seg->sides[side].wall_num].type;
 132→	flags = Walls[seg->sides[side].wall_num].flags;
 133→
 134→	if (type == WALL_OPEN)
 135→		return WID_NO_WALL;
 136→
 137→	if (type == WALL_ILLUSION) 
 138→	{
 139→		if (Walls[seg->sides[side].wall_num].flags & WALL_ILLUSION_OFF)
 140→			return WID_NO_WALL;
 141→		else 
 142→		{
 143→			if (check_transparency(seg, side))
 144→				return WID_TRANSILLUSORY_WALL;
 145→			else
 146→				return WID_ILLUSORY_WALL;
 147→		}
 148→	}
 149→
 150→	if (type == WALL_BLASTABLE) 
 151→	{
 152→		if (flags & WALL_BLASTED)
 153→			return WID_TRANSILLUSORY_WALL;
 154→
 155→		if (check_transparency(seg, side))
 156→			return WID_TRANSPARENT_WALL;
 157→		else
 158→			return WID_WALL;
 159→	}
 160→
 161→	if (flags & WALL_DOOR_OPENED)
 162→		return WID_TRANSILLUSORY_WALL;
 163→
 164→	state = Walls[seg->sides[side].wall_num].state;
 165→	if ((type == WALL_DOOR) && (state == WALL_DOOR_OPENING))
 166→		return WID_TRANSPARENT_WALL;
 167→
 168→	// If none of the above flags are set, there is no doorway.
 169→	if (check_transparency(seg, side))
 170→		return WID_TRANSPARENT_WALL;
 171→	else
 172→		return WID_WALL; // There are children behind the door.
 173→}
