 222→//set the tmap_num or tmap_num2 field for a wall/door
 223→void wall_set_tmap_num(segment* seg, int side, segment* csegp, int cside, int anim_num, int frame_num)
 224→{
 225→	wclip* anim = &WallAnims[anim_num];
 226→	int tmap = anim->frames[frame_num];
 227→
 228→	if (Newdemo_state == ND_STATE_PLAYBACK) return;
 229→
 230→	if (anim->flags & WCF_TMAP1) 
 231→	{
 232→		seg->sides[side].tmap_num = csegp->sides[cside].tmap_num = tmap;
 233→		if (Newdemo_state == ND_STATE_RECORDING)
 234→			newdemo_record_wall_set_tmap_num1(seg - Segments, side, csegp - Segments, cside, tmap);
 235→	}
 236→	else 
 237→	{
 238→		Assert(tmap != 0 && seg->sides[side].tmap_num2 != 0);
 239→		seg->sides[side].tmap_num2 = csegp->sides[cside].tmap_num2 = tmap;
 240→		if (Newdemo_state == ND_STATE_RECORDING)
 241→			newdemo_record_wall_set_tmap_num2(seg - Segments, side, csegp - Segments, cside, tmap);
 242→	}
 243→}
