 247→//when the wall has used all its hitpoints, this will destroy it
 248→void blast_blastable_wall(segment* seg, int side)
 249→{
 250→	int Connectside;
 251→	segment* csegp;
 252→	int a, n;
 253→
 254→	Assert(seg->sides[side].wall_num != -1);
 255→
 256→	csegp = &Segments[seg->children[side]];
 257→	Connectside = find_connect_side(seg, csegp);
 258→	Assert(Connectside != -1);
 259→
 260→	kill_stuck_objects(seg->sides[side].wall_num);
 261→	kill_stuck_objects(csegp->sides[Connectside].wall_num);
 262→
 263→	a = Walls[seg->sides[side].wall_num].clip_num;
 264→	n = WallAnims[a].num_frames;
 265→
 266→	if (!(WallAnims[Walls[seg->sides[side].wall_num].clip_num].flags & WCF_EXPLODES))
 267→		wall_set_tmap_num(seg, side, csegp, Connectside, a, n - 1);
 268→
 269→	Walls[seg->sides[side].wall_num].flags |= WALL_BLASTED;
 270→	Walls[csegp->sides[Connectside].wall_num].flags |= WALL_BLASTED;
 271→
 272→	//if this is an exploding wall, explode it
 273→	if (WallAnims[Walls[seg->sides[side].wall_num].clip_num].flags & WCF_EXPLODES)
 274→		explode_wall(seg - Segments, side);
 275→}
