 278→//-----------------------------------------------------------------
 279→// Destroys a blastable wall.
 280→void wall_destroy(segment* seg, int side)
 281→{
 282→	Assert(seg->sides[side].wall_num != -1);
 283→	Assert(seg - Segments != 0);
 284→
 285→	if (Walls[seg->sides[side].wall_num].type == WALL_BLASTABLE)
 286→		blast_blastable_wall(seg, side);
 287→	else
