 291→//-----------------------------------------------------------------
 292→// Deteriorate appearance of wall. (Changes bitmap (paste-ons)) 
 293→void wall_damage(segment* seg, int side, fix damage)
 294→{
 295→	int a, i, n;
 296→
 297→	if (seg->sides[side].wall_num == -1) 
 298→	{
 299→		mprintf((0, "Damaging illegal wall\n"));
 300→		return;
 301→	}
 302→
 303→	if (Walls[seg->sides[side].wall_num].type != WALL_BLASTABLE)
 304→		return;
 305→
 306→	if (!(Walls[seg->sides[side].wall_num].flags & WALL_BLASTED))
 307→	{
 308→		int Connectside;
 309→		segment* csegp;
 310→
 311→		csegp = &Segments[seg->children[side]];
 312→		Connectside = find_connect_side(seg, csegp);
 313→		Assert(Connectside != -1);
 314→
 315→		Walls[seg->sides[side].wall_num].hps -= damage;
 316→		Walls[csegp->sides[Connectside].wall_num].hps -= damage;
 317→
 318→		a = Walls[seg->sides[side].wall_num].clip_num;
 319→		n = WallAnims[a].num_frames;
 320→
 321→		if (Walls[seg->sides[side].wall_num].hps < WALL_HPS * 1 / n) 
 322→		{
 323→			blast_blastable_wall(seg, side);
 324→#ifdef NETWORK
 325→			if (Game_mode & GM_MULTI)
 326→				multi_send_door_open(seg - Segments, side);
 327→#endif
 328→		}
 329→		else
 330→			for (i = 0; i < n; i++)
 331→				if (Walls[seg->sides[side].wall_num].hps < WALL_HPS * (n - i) / n) 
 332→				{
 333→					wall_set_tmap_num(seg, side, csegp, Connectside, a, i);
 334→				}
 335→	}
 336→}
