 339→//-----------------------------------------------------------------
 340→// Opens a door 
 341→void wall_open_door(segment* seg, int side)
 342→{
 343→	wall* w;
 344→	active_door* d;
 345→	int Connectside;
 346→	segment* csegp;
 347→
 348→	Assert(seg->sides[side].wall_num != -1); 	//Opening door on illegal wall
 349→
 350→	w = &Walls[seg->sides[side].wall_num];
 351→
 352→	//kill_stuck_objects(seg->sides[side].wall_num);
 353→
 354→	if (w->state == WALL_DOOR_OPENING)		//already opening
 355→		return;
 356→
 357→	if (w->state == WALL_DOOR_WAITING)		//open, waiting to close
 358→		return;
 359→
 360→	if (w->state != WALL_DOOR_CLOSED) //reuse door
 361→	{		
 362→		int i;
 363→
 364→		d = NULL;
 365→
 366→		for (i = 0; i < Num_open_doors; i++) //find door
 367→		{
 368→			d = &ActiveDoors[i];
 369→
 370→			if (d->front_wallnum[0] == w - Walls || d->back_wallnum[0] == w - Walls || (d->n_parts == 2 && (d->front_wallnum[1] == w - Walls || d->back_wallnum[1] == w - Walls)))
 371→				break;
 372→		}
 373→
 374→		Assert(i < Num_open_doors);				//didn't find door!
 375→		Assert(d != NULL); // Get John!
 376→
 377→		d->time = WallAnims[w->clip_num].play_time - d->time;
 378→
 379→		if (d->time < 0)
 380→			d->time = 0;
 381→
 382→	}
 383→	else 
 384→	{											//create new door
 385→		d = &ActiveDoors[Num_open_doors];
 386→		d->time = 0;
 387→		Num_open_doors++;
 388→		Assert(Num_open_doors < MAX_DOORS);
 389→	}
 390→
 391→	w->state = WALL_DOOR_OPENING;
 392→
 393→	// So that door can't be shot while opening
 394→	csegp = &Segments[seg->children[side]];
 395→	Connectside = find_connect_side(seg, csegp);
 396→	Assert(Connectside != -1);
 397→
 398→	Walls[csegp->sides[Connectside].wall_num].state = WALL_DOOR_OPENING;
 399→
 400→	//kill_stuck_objects(csegp->sides[Connectside].wall_num);
 401→
 402→	d->front_wallnum[0] = seg->sides[side].wall_num;
 403→	d->back_wallnum[0] = csegp->sides[Connectside].wall_num;
 404→
 405→	Assert(seg - Segments != -1);
 406→
 407→#ifndef SHAREWARE
 408→	if (Newdemo_state == ND_STATE_RECORDING) 
 409→	{
 410→		newdemo_record_door_opening(seg - Segments, side);
 411→	}
 412→#endif
 413→
 414→	if (w->linked_wall != -1) 
 415→	{
 416→		wall* w2;
 417→		segment* seg2;
 418→
 419→		w2 = &Walls[w->linked_wall];
 420→		seg2 = &Segments[w2->segnum];
 421→
 422→		Assert(w2->linked_wall == seg->sides[side].wall_num);
 423→		//Assert(!(w2->flags & WALL_DOOR_OPENING  ||  w2->flags & WALL_DOOR_OPENED));
 424→
 425→		w2->state = WALL_DOOR_OPENING;
 426→
 427→		csegp = &Segments[seg2->children[w2->sidenum]];
 428→		Connectside = find_connect_side(seg2, csegp);
 429→		Assert(Connectside != -1);
 430→		Walls[csegp->sides[Connectside].wall_num].state = WALL_DOOR_OPENING;
 431→
 432→		d->n_parts = 2;
 433→		d->front_wallnum[1] = w->linked_wall;
 434→		d->back_wallnum[1] = csegp->sides[Connectside].wall_num;
 435→	}
 436→	else
 437→		d->n_parts = 1;
 438→
 439→
 440→	if (Newdemo_state != ND_STATE_PLAYBACK)
 441→	{
 442→		// NOTE THE LINK TO ABOVE!!!!
 443→		vms_vector cp;
 444→		compute_center_point_on_side(&cp, seg, side);
 445→		if (WallAnims[w->clip_num].open_sound > -1)
 446→			digi_link_sound_to_pos(WallAnims[w->clip_num].open_sound, seg - Segments, side, &cp, 0, F1_0);
 447→
 448→	}
 449→}
