 451→//-----------------------------------------------------------------
 452→// This function closes the specified door and restores the closed
 453→//  door texture.  This is called when the animation is done
 454→void wall_close_door(int door_num)
 455→{
 456→	int p;
 457→	active_door* d;
 458→	int i;
 459→
 460→	d = &ActiveDoors[door_num];
 461→
 462→	for (p = 0; p < d->n_parts; p++) 
 463→	{
 464→		wall* w;
 465→		int Connectside, side;
 466→		segment* csegp, * seg;
 467→
 468→		w = &Walls[d->front_wallnum[p]];
 469→
 470→		seg = &Segments[w->segnum];
 471→		side = w->sidenum;
 472→
 473→		Assert(seg->sides[side].wall_num != -1);		//Closing door on illegal wall
 474→
 475→		csegp = &Segments[seg->children[side]];
 476→		Connectside = find_connect_side(seg, csegp);
 477→		Assert(Connectside != -1);
 478→
 479→		Walls[seg->sides[side].wall_num].state = WALL_DOOR_CLOSED;
 480→		Walls[csegp->sides[Connectside].wall_num].state = WALL_DOOR_CLOSED;
 481→
 482→		wall_set_tmap_num(seg, side, csegp, Connectside, w->clip_num, 0);
 483→
 484→	}
 485→
 486→	for (i = door_num; i < Num_open_doors; i++)
 487→		ActiveDoors[i] = ActiveDoors[i + 1];
 488→
 489→	Num_open_doors--;
 490→
 491→}
