 494→//-----------------------------------------------------------------
 495→// Animates opening of a door.
 496→// Called in the game loop.
 497→void do_door_open(int door_num)
 498→{
 499→	int p;
 500→	active_door* d;
 501→
 502→	Assert(door_num != -1);		//Trying to do_door_open on illegal door
 503→
 504→	d = &ActiveDoors[door_num];
 505→
 506→	for (p = 0; p < d->n_parts; p++) 
 507→	{
 508→		wall* w;
 509→		int Connectside, side;
 510→		segment* csegp, * seg;
 511→		fix time_elapsed, time_total, one_frame;
 512→		int i, n;
 513→
 514→		w = &Walls[d->front_wallnum[p]];
 515→		kill_stuck_objects(d->front_wallnum[p]);
 516→		kill_stuck_objects(d->back_wallnum[p]);
 517→
 518→		seg = &Segments[w->segnum];
 519→		side = w->sidenum;
 520→
 521→		Assert(seg->sides[side].wall_num != -1);		//Trying to do_door_open on illegal wall
 522→
 523→		csegp = &Segments[seg->children[side]];
 524→		Connectside = find_connect_side(seg, csegp);
 525→		Assert(Connectside != -1);
 526→
 527→		d->time += FrameTime;
 528→
 529→		time_elapsed = d->time;
 530→		n = WallAnims[w->clip_num].num_frames;
 531→		time_total = WallAnims[w->clip_num].play_time;
 532→
 533→		one_frame = time_total / n;
 534→
 535→		i = time_elapsed / one_frame;
 536→
 537→		if (i < n)
 538→			wall_set_tmap_num(seg, side, csegp, Connectside, w->clip_num, i);
 539→
 540→		if (i > n / 2) 
 541→		{
 542→			Walls[seg->sides[side].wall_num].flags |= WALL_DOOR_OPENED;
 543→			Walls[csegp->sides[Connectside].wall_num].flags |= WALL_DOOR_OPENED;
 544→		}
 545→
 546→		if (i >= n - 1) 
 547→		{
 548→			wall_set_tmap_num(seg, side, csegp, Connectside, w->clip_num, n - 1);
 549→
 550→			// If our door is not automatic just remove it from the list.
 551→			if (!(Walls[seg->sides[side].wall_num].flags & WALL_DOOR_AUTO)) 
 552→			{
 553→				for (i = door_num; i < Num_open_doors; i++)
 554→					ActiveDoors[i] = ActiveDoors[i + 1];
 555→				Num_open_doors--;
 556→			}
 557→			else 
 558→			{
 559→
 560→				Walls[seg->sides[side].wall_num].state = WALL_DOOR_WAITING;
 561→				Walls[csegp->sides[Connectside].wall_num].state = WALL_DOOR_WAITING;
 562→
 563→				ActiveDoors[Num_open_doors].time = 0;	//counts up
 564→			}
 565→		}
 566→
 567→	}
 568→
 569→}
