 585→//-----------------------------------------------------------------
 586→// Animates and processes the closing of a door.
 587→// Called from the game loop.
 588→void do_door_close(int door_num)
 589→{
 590→	int p;
 591→	active_door* d;
 592→	wall* w;
 593→
 594→	Assert(door_num != -1);		//Trying to do_door_open on illegal door
 595→
 596→	d = &ActiveDoors[door_num];
 597→
 598→	w = &Walls[d->front_wallnum[0]];
 599→
 600→	//check for objects in doorway before closing
 601→	if (w->flags & WALL_DOOR_AUTO)
 602→		for (p = 0; p < d->n_parts; p++) 
 603→		{
 604→			int Connectside, side;
 605→			segment* csegp, * seg;
 606→			int objnum;
 607→
 608→			seg = &Segments[w->segnum];
 609→			side = w->sidenum;
 610→
 611→			csegp = &Segments[seg->children[side]];
 612→			Connectside = find_connect_side(seg, csegp);
 613→			Assert(Connectside != -1);
 614→
 615→			//go through each object in each of two segments, and see if
 616→			//it pokes into the connecting seg
 617→
 618→			for (objnum = seg->objects; objnum != -1; objnum = Objects[objnum].next)
 619→				if (check_poke(objnum, seg - Segments, side))
 620→					return;		//abort!
 621→
 622→			for (objnum = csegp->objects; objnum != -1; objnum = Objects[objnum].next)
 623→				if (check_poke(objnum, csegp - Segments, Connectside))
 624→					return;		//abort!
 625→		}
 626→
 627→	for (p = 0; p < d->n_parts; p++) 
 628→	{
 629→		wall* w;
 630→		int Connectside, side;
 631→		segment* csegp, * seg;
 632→		fix time_elapsed, time_total, one_frame;
 633→		int i, n;
 634→
 635→		w = &Walls[d->front_wallnum[p]];
 636→
 637→		seg = &Segments[w->segnum];
 638→		side = w->sidenum;
 639→
 640→		if (seg->sides[side].wall_num == -1) 
 641→		{
 642→			mprintf((0, "Trying to do_door_close on Illegal wall\n"));
 643→			return;
 644→		}
 645→
 646→		//if here, must be auto door
 647→		Assert(Walls[seg->sides[side].wall_num].flags & WALL_DOOR_AUTO);
 648→
 649→		// Otherwise, close it.
 650→		csegp = &Segments[seg->children[side]];
 651→		Connectside = find_connect_side(seg, csegp);
 652→		Assert(Connectside != -1);
 653→
 654→
 655→		if (Newdemo_state != ND_STATE_PLAYBACK)
 656→			// NOTE THE LINK TO ABOVE!!
 657→			if (p == 0)	//only play one sound for linked doors
 658→				if (d->time == 0) //first time
 659→				{
 660→					vms_vector cp;
 661→					compute_center_point_on_side(&cp, seg, side);
 662→					if (WallAnims[w->clip_num].close_sound > -1)
 663→						digi_link_sound_to_pos(WallAnims[Walls[seg->sides[side].wall_num].clip_num].close_sound, seg - Segments, side, &cp, 0, F1_0);
 664→				}
 665→
 666→		d->time += FrameTime;
 667→
 668→		time_elapsed = d->time;
 669→		n = WallAnims[w->clip_num].num_frames;
 670→		time_total = WallAnims[w->clip_num].play_time;
 671→
 672→		one_frame = time_total / n;
 673→
 674→		i = n - time_elapsed / one_frame - 1;
 675→
 676→		if (i < n / 2) 
 677→		{
 678→			Walls[seg->sides[side].wall_num].flags &= ~WALL_DOOR_OPENED;
 679→			Walls[csegp->sides[Connectside].wall_num].flags &= ~WALL_DOOR_OPENED;
 680→		}
 681→
 682→		// Animate door.
 683→		if (i > 0) 
 684→		{
 685→			wall_set_tmap_num(seg, side, csegp, Connectside, w->clip_num, i);
 686→
 687→			Walls[seg->sides[side].wall_num].state = WALL_DOOR_CLOSING;
 688→			Walls[csegp->sides[Connectside].wall_num].state = WALL_DOOR_CLOSING;
 689→
 690→			ActiveDoors[Num_open_doors].time = 0;		//counts up
 691→
 692→		}
 693→		else
 694→			wall_close_door(door_num);
 695→	}
 696→}
