 780→//-----------------------------------------------------------------
 781→// Determines what happens when a wall is shot
 782→//returns info about wall.  see wall.h for codes
 783→//obj is the object that hit...either a weapon or the player himself
 784→//playernum is the number the player who hit the wall or fired the weapon,
 785→//or -1 if a robot fired the weapon
 786→int wall_hit_process(segment* seg, int side, fix damage, int playernum, object* obj)
 787→{
 788→	wall* w;
 789→	fix	show_message;
 790→
 791→	Assert(seg - Segments != -1);
 792→
 793→	// If it is not a "wall" then just return.
 794→	if (seg->sides[side].wall_num < 0)
 795→		return WHP_NOT_SPECIAL;
 796→
 797→	w = &Walls[seg->sides[side].wall_num];
 798→
 799→	if (Newdemo_state == ND_STATE_RECORDING)
 800→		newdemo_record_wall_hit_process(seg - Segments, side, damage, playernum);
 801→
 802→	if (w->type == WALL_BLASTABLE) 
 803→	{
 804→		wall_damage(seg, side, damage);
 805→		return WHP_BLASTABLE;
 806→	}
 807→
 808→	if (playernum != Player_num)	//return if was robot fire
 809→		return WHP_NOT_SPECIAL;
 810→
 811→	Assert(playernum > -1);
 812→
 813→	//	Determine whether player is facing door he hit.  If not, don't say negative
 814→	//	messages because he probably didn't intentionally hit the door.
 815→	if (obj->type == OBJ_PLAYER)
 816→		show_message = (vm_vec_dot(&obj->orient.fvec, &obj->mtype.phys_info.velocity) > 0);
 817→	else
 818→		show_message = 1;
 819→
 820→	if (w->keys == KEY_BLUE)
 821→		if (!(Players[playernum].flags & PLAYER_FLAGS_BLUE_KEY)) 
 822→		{
 823→			if (playernum == Player_num)
 824→				if (show_message)
 825→					HUD_init_message("%s %s", TXT_BLUE, TXT_ACCESS_DENIED);
 826→			return WHP_NO_KEY;
 827→		}
 828→
 829→	if (w->keys == KEY_RED)
 830→		if (!(Players[playernum].flags & PLAYER_FLAGS_RED_KEY)) 
 831→		{
 832→			if (playernum == Player_num)
 833→				if (show_message)
 834→					HUD_init_message("%s %s", TXT_RED, TXT_ACCESS_DENIED);
 835→			return WHP_NO_KEY;
 836→		}
 837→
 838→	if (w->keys == KEY_GOLD)
 839→		if (!(Players[playernum].flags & PLAYER_FLAGS_GOLD_KEY)) 
 840→		{
 841→			if (playernum == Player_num)
 842→				if (show_message)
 843→					HUD_init_message("%s %s", TXT_YELLOW, TXT_ACCESS_DENIED);
 844→			return WHP_NO_KEY;
 845→		}
 846→
 847→	if (w->type == WALL_DOOR)
 848→		if ((w->flags & WALL_DOOR_LOCKED) && !(special_boss_opening_allowed(seg - Segments, side))) 
 849→		{
 850→			if (playernum == Player_num)
 851→				if (show_message)
 852→					HUD_init_message(TXT_CANT_OPEN_DOOR);
 853→			return WHP_NO_KEY;
 854→		}
 855→		else 
 856→		{
 857→			if (w->state != WALL_DOOR_OPENING)
 858→			{
 859→				wall_open_door(seg, side);
 860→#ifdef NETWORK
 861→				if (Game_mode & GM_MULTI)
 862→					multi_send_door_open(seg - Segments, side);
 863→#endif
 864→			}
 865→			return WHP_DOOR;
 866→
 867→		}
 868→
 869→	return WHP_NOT_SPECIAL;		//default is treat like normal wall
 870→}
