1033→//	----------------------------------------------------------------------------------------------------
1034→//	Door with wall index wallnum is opening, kill all objects stuck in it.
1035→void kill_stuck_objects(int wallnum)
1036→{
1037→#ifdef USE_OX_BRIDGE
1038→	{
1039→		static int registered = 0;
1040→		if (!registered) {
1041→			cd_ox_register_wall_kill_stuck_effects(
1042→				/* fetch_kill_stuck_data: [is_d2, num_stuck, (wallnum, objnum, obj_type) x 32] */
1043→				[](int wallnum_arg, int32_t* out) {
1044→					out[0] = 0; /* is_d2 = false (D1) */
1045→					out[1] = Num_stuck_objects;
1046→					for (int i = 0; i < MAX_STUCK_OBJECTS; i++) {
1047→						int base = 2 + i * 3;
1048→						out[base]     = Stuck_objects[i].wallnum;
1049→						out[base + 1] = Stuck_objects[i].objnum;
1050→						out[base + 2] = (Stuck_objects[i].wallnum != -1)
1051→							? Objects[Stuck_objects[i].objnum].type : -1;
1052→					}
1053→				},
1054→				/* write_kill_stuck_objects: [new_num_stuck, n_matches, (slot, objnum, is_weapon) x n] */
1055→				[](const int32_t* packed, int len) {
1056→					if (len < 2) return;
1057→					Num_stuck_objects = packed[0];
1058→					int n_matches = packed[1];
1059→					for (int j = 0; j < n_matches && (2 + j * 3 + 2) < len; j++) {
1060→						int slot = packed[2 + j * 3];
1061→						int objnum = packed[2 + j * 3 + 1];
1062→						int is_weapon = packed[2 + j * 3 + 2];
1063→						if (is_weapon) {
1064→							Objects[objnum].lifeleft = F1_0 / 4;
1065→						}
1066→						Stuck_objects[slot].wallnum = -1;
1067→					}
1068→				},
1069→				/* flush_fcd_cache — D1 doesn't call it, but register a no-op */
1070→				[]() { });
1071→			registered = 1;
1072→		}
1073→		cd_ox_kill_stuck_objects(wallnum);
1074→		return;
1075→	}
1076→#endif
1077→	int	i;
1078→
1079→	if (Num_stuck_objects == 0)
1080→		return;
1081→
1082→	Num_stuck_objects = 0;
1083→
1084→	for (i = 0; i < MAX_STUCK_OBJECTS; i++)
1085→		if (Stuck_objects[i].wallnum == wallnum)
1086→		{
1087→			if (Objects[Stuck_objects[i].objnum].type == OBJ_WEAPON)
1088→			{
1089→				Objects[Stuck_objects[i].objnum].lifeleft = F1_0 / 4;
1090→				mprintf((0, "Removing object %i from wall %i\n", Stuck_objects[i].objnum, wallnum));
1091→			}
1092→			else
1093→				mprintf((0, "Warning: Stuck object of type %i, expected to be of type %i, see wall.c\n", Objects[Stuck_objects[i].objnum].type, OBJ_WEAPON));
1094→			// Int3();	//	What?  This looks bad.  Object is not a weapon and it is stuck in a wall!
1095→			Stuck_objects[i].wallnum = -1;
1096→		}
1097→		else if (Stuck_objects[i].wallnum != -1)
1098→			Num_stuck_objects++;
1099→}
